targets.expr:
avg by (user_unit) (
  last_over_time(
    {user_unit="coinbase-trader-ws.service"} 
    | regexp `PnL: \$(?P<pnl_str>-?[0-9,.]+)`
    | line_format `{{ .pnl_str | replace "," "" }}`
    | regexp `(?P<pnl>-?[0-9.]+)`
    | unwrap pnl [1h]
  )
)

last_over_time(
  {user_unit="phar-liquidity-bot.service"} 
  | regexp `Total reward collections: (?P<rewards>\d+)` 
  | unwrap rewards [1h]
)

last_over_time(
  {user_unit="phar-liquidity-bot.service"}
  |= "Fees earned:"
  | regexp `Fees earned: (?P<fees>[\d.-]+) WAVAX`
  | unwrap fees [10m]
)

last_over_time(
  {user_unit="phar-liquidity-bot.service"}
  |= "Net P&L:"
  | regexp `Net P&L: (?P<pnl>[\d.-]+) WAVAX`
  | unwrap pnl [10m]
)
